import numpy as np

def dropout(x: np.ndarray, p: float, training: bool = True,
            rng: np.random.Generator = None) -> np.ndarray:
    if not training:
        return x
    if p == 0.0:
        return x
    if p == 1.0:
        return np.zeros_like(x)
    if rng is None:
        rng = np.random.default_rng()
    mask = rng.random(x.shape) >= p
    return x * mask / (1.0 - p)
